/**
 * @summary Get plan comparison data
 */
export const getGetCompareOptionsUrl = (params?: GetCompareOptionsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/employee/compare?${stringifiedParams}`
    : `/api/employee/compare`;
};

export const getCompareOptions = async (
  params?: GetCompareOptionsParams,
  options?: RequestInit,
): Promise<PlanComparisonResponse> => {
  return customFetch<PlanComparisonResponse>(getGetCompareOptionsUrl(params), {
    ...options,
    method: "GET",
  });
};

